#include <iostream>
#include <array>
#include <utility>

int main()
{
    std::array<int, 5> a { 3, 9, 1, 7, 5 };
    int n = static_cast<int>(a.size());

    for (int i = 0; i < n - 1; ++i)
    {
        int maxIdx = i;
        for (int j = i + 1; j < n; ++j)
        {
            if (a[j] > a[maxIdx])   // fixed: > for descending
                maxIdx = j;
        }
        std::swap(a[i], a[maxIdx]);
    }

    for (int i = 0; i < n; ++i)
    {
        if (i > 0) std::cout << ' ';
        std::cout << a[i];
    }
    std::cout << '\n';

    return 0;
}
